const body = $input.first().json.body || $input.first().json;
const event = body.event || body.type;

const messageEvents = ['messages.upsert', 'messages.update'];
if (!messageEvents.includes(event)) return [];

const message = body.data?.message || body.message || {};
const key = body.data?.key || body.key || {};

// Para messages.update sem conteudo, ignorar
if (event === 'messages.update' && !message.conversation && !message.extendedTextMessage) return [];

const tipo = message.audioMessage ? 'audio'
           : message.imageMessage ? 'image'
           : message.documentMessage ? 'document'
           : 'text';

const conteudo = message.conversation
               || message.extendedTextMessage?.text
               || null;

// Extrair identificador_externo do payload (campo padrão do Redrive para multi-agente)
const identificador_externo = body.data?.agentId || body.agentId || body.metadados?.agentId || null;

return [{
  json: {
    event,
    tipo,
    from_me: key.fromMe || false,
    session_id:   body.instance || $env.ML_EVOLUTION_INSTANCE,
    remote_jid:   key.remoteJid,
    message_id:   key.id,
    conteudo_raw: conteudo,
    audio_url:    message.audioMessage?.url || null,
    duracao_audio: message.audioMessage?.seconds || null,
    identificador_externo,
    metadados:    body
  }
}];

const payload = $('Normalizar Payload').first().json;
const lookup = $input.first().json;
const area = lookup.area || 'comercial';
const projeto_id = lookup.projeto_id || null;
const numero_tipo = lookup.numero_tipo || 'mono';
const agente_default_id = lookup.agente_default_id || null;

return [{ json: { ...payload, area, projeto_id, numero_tipo, agente_default_id } }];

const dados = $('Enriquecer com Setor').first().json;
const tipo = dados.numero_tipo || 'mono';

let agente_humano_id = null;

if (tipo === 'mono') {
  agente_humano_id = dados.agente_default_id || null;
} else {
  // multi: tenta pegar do lookup, se falhou fica null
  try {
    const lookupResult = $('Lookup Agente Multi').first().json;
    agente_humano_id = lookupResult.agente_humano_id || null;
  } catch (e) {
    agente_humano_id = null;
  }
}

return [{ json: { ...dados, agente_humano_id } }];

// Prepara dados do áudio + transcrição para inserir no Postgres
const payload = $('Resolver Atendente').first().json;
const whisper = $input.first().json;

return [{
  json: {
    mensagem: {
      area:         payload.area,
      fonte:        'whatsapp',
      session_id:   payload.session_id,
      projeto_id:   payload.projeto_id,
      remote_jid:   payload.remote_jid,
      message_id:   payload.message_id,
      tipo:         'audio',
      conteudo_raw: whisper.text,
      audio_url:    payload.audio_url,
      duracao_audio: payload.duracao_audio,
      status:       'processada',
      agente_humano_id: payload.agente_humano_id || null,
      metadados:    payload.metadados
    },
    transcricao: {
      texto:     whisper.text,
      idioma:    whisper.language || 'pt',
      confianca: whisper.segments?.[0]?.avg_logprob ? Math.exp(whisper.segments[0].avg_logprob) : null,
      provider:  'groq-whisper'
    }
  }
}];

// Prepara dados de mensagem de texto para inserir no Postgres
const payload = $input.first().json;

return [{
  json: {
    mensagem: {
      area:         payload.area,
      fonte:        'whatsapp',
      session_id:   payload.session_id,
      projeto_id:   payload.projeto_id,
      remote_jid:   payload.remote_jid,
      message_id:   payload.message_id,
      tipo:         'text',
      conteudo_raw: payload.conteudo_raw,
      audio_url:    null,
      duracao_audio: null,
      status:       'processada',
      agente_humano_id: payload.agente_humano_id || null,
      metadados:    payload.metadados
    },
    transcricao: null
  }
}];

// Log de erro estruturado — não quebra o pipeline
const error = $input.first().json;
console.error('[ML-CAPTURA] Erro no pipeline:', JSON.stringify({
  timestamp: new Date().toISOString(),
  error: error.message || 'Erro desconhecido',
  node: $runIndex
}));
return [{ json: { status: 'error_logged', error: error.message } }];
